def validate(args, output):
    order, s = args[0], args[1]
    if not isinstance(output, str):
        return False
    from collections import Counter
    if Counter(output) != Counter(s):
        return False
    rank = {c: i for i, c in enumerate(order)}
    # the subsequence of output restricted to chars in order must be non-decreasing by rank
    last = -1
    for ch in output:
        if ch in rank:
            if rank[ch] < last:
                return False
            last = rank[ch]
    return True

