function validate(args, output) {
    const order = args[0], s = args[1];
    if (typeof output !== 'string') return false;
    const ca = {}, cb = {};
    for (const ch of output) ca[ch] = (ca[ch] || 0) + 1;
    for (const ch of s) cb[ch] = (cb[ch] || 0) + 1;
    const keys = new Set([...Object.keys(ca), ...Object.keys(cb)]);
    for (const k of keys) if ((ca[k] || 0) !== (cb[k] || 0)) return false;
    const rank = {};
    for (let i = 0; i < order.length; i++) rank[order[i]] = i;
    let last = -1;
    for (const ch of output) {
        if (ch in rank) {
            if (rank[ch] < last) return false;
            last = rank[ch];
        }
    }
    return true;
}

