class Solution:
    def customSortString(self, order, s):
        from collections import Counter
        cnt = Counter(s)
        res = []
        for ch in order:
            if cnt[ch]:
                res.append(ch * cnt[ch])
                cnt[ch] = 0
        for ch in sorted(cnt):
            if cnt[ch]:
                res.append(ch * cnt[ch])
        return ''.join(res)

