class Solution:
    def customSortString(self, order, s):
        from collections import Counter
        cnt = Counter(s)
        out = []
        for ch in order:
            if ch in cnt:
                out.append(ch * cnt[ch])
                del cnt[ch]
        for ch in sorted(cnt):
            out.append(ch * cnt[ch])
        return ''.join(out)

