var customSortString = function(order, s) {
    const cnt = {};
    for (const ch of s) cnt[ch] = (cnt[ch] || 0) + 1;
    const out = [];
    for (const ch of order) {
        if (cnt[ch]) {
            out.push(ch.repeat(cnt[ch]));
            delete cnt[ch];
        }
    }
    for (const ch of Object.keys(cnt).sort()) {
        out.push(ch.repeat(cnt[ch]));
    }
    return out.join('');
};
